	void operatorFeedbackFusionPathReceivesBackgroundSampledAndLearnedFilterSources(@TempDir File dataDir)
			throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc")
				.setOptimizerSamplingEnabled(false)
				.setBackgroundRawSamplingMaxMillisPerCycle(0L);
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSparseOptionalFanout(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store);

			String query = filteredLeftJoinFanoutQuery();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized);
			}
			Filter filter = firstFilter(query);
			int sampled = 0;
			for (int i = 0; i < 5; i++) {
				sampled += store.getBackingStore().runBackgroundFilterSamplingCycle(5_000L);
				EvaluationStatistics.FilterPassEstimate estimate = store.getBackingStore()
						.getEvaluationStatistics()
						.estimateFilterPass(filter);
				if (estimate.getSource() == EvaluationStatistics.FilterPassEstimate.Source.SAMPLED) {
					break;
				}
			}
			assertTrue(sampled > 0, "Expected background sampler to process the position filter");
			assertEquals(EvaluationStatistics.FilterPassEstimate.Source.SAMPLED,
					store.getBackingStore().getEvaluationStatistics().estimateFilterPass(filter).getSource(),
					"Expected background sampling to feed the filter estimator before operator-feedback planning");

			try (SailRepositoryConnection connection = repository.getConnection()) {
				String sampledPlan = connection.prepareTupleQuery(query)
						.explain(Explanation.Level.Optimized)
						.toString();

				assertTrue(
						containsSampledFilterEvidence(sampledPlan) || containsFiniteFilterRewriteEvidence(sampledPlan),
						"Expected optimized planning to receive background-sampled filter evidence or a stronger "
								+ "finite-domain filter rewrite before runtime learning can supersede it:\n"
								+ sampledPlan);

				assertEquals(EXPECTED_FILTERED_LEFT_JOIN_ROWS, count(connection, query));
				connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);

				String trainedPlan = connection.prepareTupleQuery(query)
						.explain(Explanation.Level.Optimized)
						.toString();

				assertFusedOperatorOrFiniteFilterCostPath(trainedPlan,
						LmdbOperatorFeedbackStats.LEARNED_LEFT_JOIN_SURFACE,
						"Operator feedback or the stronger finite-domain filter rewrite must affect the planned "
								+ "estimate, not only final annotation");
				assertTrue(containsLearnedFilterEvidence(trainedPlan)
						|| containsSampledFilterEvidence(trainedPlan)
						|| containsFiniteFilterRewriteEvidence(trainedPlan),
						"Fused operator estimates must retain the strongest available filter evidence from the base "
								+ "estimator:\n"
								+ trainedPlan);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static long count(SailRepositoryConnection connection, String query) {
		TupleQuery tupleQuery = connection.prepareTupleQuery(query);
		try (TupleQueryResult result = tupleQuery.evaluate()) {
			assertTrue(result.hasNext(), "Expected count result");
			return ((Literal) result.next().getValue("count")).longValue();
		}
	}

	private static String leftJoinFanoutQuery() {
		return String.join("\n",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  ?person <urn:test:operator-feedback:memberOf> ?org .",
				"  ?org <urn:test:operator-feedback:department> ?department .",
				"  ?department <urn:test:operator-feedback:makesOffer> ?offer .",
				"  ?offer <urn:test:operator-feedback:page> ?page .",
				"  OPTIONAL {",
				"    ?page <urn:test:operator-feedback:review> ?review .",
				"  }",
				"}");
	}

	private static String optionalUnionFanoutQuery() {
		return String.join("\n",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  ?person <urn:test:operator-feedback:memberOf> ?org .",
				"  ?org <urn:test:operator-feedback:department> ?department .",
				"  ?department <urn:test:operator-feedback:makesOffer> ?offer .",
				"  ?offer <urn:test:operator-feedback:page> ?page .",
				"  OPTIONAL {",
				"    { ?page <urn:test:operator-feedback:review> ?opt . }",
				"    UNION",
				"    { ?person <urn:test:operator-feedback:award> ?opt . }",
				"  }",
				"}");
	}

	private static String filteredLeftJoinFanoutQuery() {
		return String.join("\n",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  ?person <urn:test:operator-feedback:memberOf> ?org .",
				"  ?person <urn:test:operator-feedback:position> ?position .",
				"  FILTER(?position > 2)",
				"  ?org <urn:test:operator-feedback:department> ?department .",
				"  ?department <urn:test:operator-feedback:makesOffer> ?offer .",
				"  ?offer <urn:test:operator-feedback:page> ?page .",
				"  OPTIONAL {",
				"    ?page <urn:test:operator-feedback:review> ?review .",
				"  }",
				"}");
	}

	private static void assertFusedOperatorCostPath(String plan, String expectedSource, String message) {
		assertTrue(containsFusedOperatorCostPath(plan, expectedSource),
				message + ":\n" + plan);
		assertSelectedPlannerCostPath(plan);
	}

	private static void assertFusedOperatorOrFiniteFilterCostPath(String plan, String expectedSource, String message) {
		assertTrue(containsFusedOperatorCostPath(plan, expectedSource) || containsFiniteFilterCostPath(plan),
				message + ":\n" + plan);
		assertSelectedPlannerCostPath(plan);
	}

	private static boolean containsFusedOperatorCostPath(String plan, String expectedSource) {
		return plan.contains("plannedEstimateFusion=operator_feedback")
				&& plan.contains("plannedOperatorFeedbackSource=" + expectedSource);
	}

	private static boolean containsFiniteFilterCostPath(String plan) {
		return containsFiniteFilterRewriteEvidence(plan) && plan.contains("costing=dynamic");
	}

	private static void assertSelectedPlannerCostPath(String plan) {
		assertTrue(plan.contains("plannedEstimateUsage=alternative_ranking")
				|| plan.contains("plannedEstimateUsage=join_order_candidate"),
				"Operator feedback must be shown only when it was a selected planner ranking input:\n" + plan);
		assertTrue(plan.contains("plannedEstimateDecisionId="),
				"Selected planner estimates must be tied back to the chosen decision:\n" + plan);
		assertTrue(plan.contains("plannedCardinalityRows="),
				"Selected planner estimates must expose structured cardinality, not only legacy resultSizeEstimate:\n"
						+ plan);
		assertTrue(plan.contains("plannedCostWorkRows=") && plan.contains("plannedObjectiveScore="),
				"Selected planner estimates must expose structured cost used for ranking:\n" + plan);
	}

	private static boolean containsLearnedFilterEvidence(String plan) {
		return plan.contains("filterSelectivitySource=learned_filter")
				|| plan.contains("plannedBaseFilterSelectivitySources=learned_filter")
				|| plan.contains("sources={learned_filter=")
				|| plan.contains("sources={sampled=1, learned_filter=")
				|| plan.contains("sources={learned_filter=1, sampled=");
	}

	private static boolean containsSampledFilterEvidence(String plan) {
		return plan.contains("filterSelectivitySource=sampled")
				|| plan.contains("plannedBaseFilterSelectivitySources=sampled")
				|| plan.contains("sources={sampled=");
	}

	private static boolean containsFiniteFilterRewriteEvidence(String plan) {
		return plan.contains("filterInValuesEquivalent") || plan.contains("selected=finite-anchor:");
	}

	private static Filter firstFilter(String query) {
		AtomicReference<Filter> filter = new AtomicReference<>();
		QueryParserUtil.parseQuery(QueryLanguage.SPARQL, query, null)
				.getTupleExpr()
				.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>(true) {
					@Override
					public void meet(Filter node) {
						filter.compareAndSet(null, node);
						super.meet(node);
					}
				});
		return filter.get();
	}

	private static void loadSparseOptionalFanout(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int orgIndex = 0; orgIndex < ORG_COUNT; orgIndex++) {
				Resource org = VF.createIRI("urn:test:operator-feedback:org:" + orgIndex);
				for (int personIndex = 0; personIndex < PERSONS_PER_ORG; personIndex++) {
					Resource person = VF.createIRI("urn:test:operator-feedback:person:" + orgIndex + ":"
							+ personIndex);
					connection.add(person, MEMBER_OF, org);
					connection.add(person, POSITION, VF.createLiteral((personIndex % 5) + 1));
					if (personIndex == 0) {
						connection.add(person, AWARD, VF.createIRI("urn:test:operator-feedback:award:" + orgIndex));
					}
				}
				for (int departmentIndex = 0; departmentIndex < DEPARTMENTS_PER_ORG; departmentIndex++) {
					Resource department = VF.createIRI("urn:test:operator-feedback:department:" + orgIndex + ":"
							+ departmentIndex);
					connection.add(org, DEPARTMENT, department);
					for (int offerIndex = 0; offerIndex < OFFERS_PER_DEPARTMENT; offerIndex++) {
						Resource offer = VF.createIRI("urn:test:operator-feedback:offer:" + orgIndex + ":"
								+ departmentIndex + ":" + offerIndex);
						Resource page = VF.createIRI("urn:test:operator-feedback:page:" + orgIndex + ":"
								+ departmentIndex + ":" + offerIndex);
						connection.add(department, MAKES_OFFER, offer);
						connection.add(offer, PAGE, page);
						for (int reviewIndex = 0; reviewIndex < REVIEWS_PER_PAGE; reviewIndex++) {
							connection.add(page, REVIEW, VF.createIRI("urn:test:operator-feedback:review:" + orgIndex
									+ ":" + departmentIndex + ":" + offerIndex + ":" + reviewIndex));
						}
					}
				}
			}
			connection.commit();
		}
	}
